const data = $input.first().json;
const places = data.places || [];
const pendingData = $('Get Next Pending Row').first().json;
const TARGET_ITEMS = 6;
const TARGET_DURATION_SECS = 20;
const picked = [];

function firstHighlight(place) {
  const hl = (place.highlights || []).filter(h => h && h.trim());
  return hl.length > 0 ? hl[0].trim() : '';
}

for (const place of places) {
  if (picked.length >= TARGET_ITEMS) break;
  const media = place.media || [];
  const video = media.find(m => m.type === 'video' && m.url);
  if (video) {
    picked.push({ source: 'url', url: video.url, media_type: 'video', title: place.name, caption_text: place.caption_text || '', caption: firstHighlight(place) });
  }
}

for (const place of places) {
  if (picked.length >= TARGET_ITEMS) break;
  const media = place.media || [];
  const alreadyPickedUrls = new Set(picked.map(p => p.url));
  for (const item of media) {
    if (picked.length >= TARGET_ITEMS) break;
    if (item.type === 'image' && item.url && !alreadyPickedUrls.has(item.url)) {
      picked.push({ source: 'url', url: item.url, media_type: 'image', title: place.name, caption_text: place.caption_text || '', caption: firstHighlight(place) });
      alreadyPickedUrls.add(item.url);
    }
  }
}

if (picked.length === 0) throw new Error('No media items found in travel-media response');

const videoCount = picked.filter(p => p.media_type === 'video').length;
const imageCount = picked.filter(p => p.media_type === 'image').length;
let totalEstimated = videoCount * 5 + imageCount * 3;
let clipVideo = 5, clipImage = 3;
if (totalEstimated < 18) {
  const scale = TARGET_DURATION_SECS / Math.max(totalEstimated, 1);
  clipVideo = Math.round(5 * scale * 10) / 10;
  clipImage = Math.round(3 * scale * 10) / 10;
} else if (totalEstimated > 22) {
  const scale = TARGET_DURATION_SECS / totalEstimated;
  clipVideo = Math.round(5 * scale * 10) / 10;
  clipImage = Math.round(3 * scale * 10) / 10;
}

return [{ json: { picked_items: picked, clip_seconds_video: String(clipVideo), clip_seconds_image: String(clipImage), estimated_duration_secs: videoCount * clipVideo + imageCount * clipImage, place_names: places.map(p => p.name), row_index: pendingData.row_index, destination: pendingData.destination } }];

